using Microsoft.AspNetCore.Mvc;namespace IntegraRP.Web.Controllers;[ApiController][Route("api")]public sealed class ApiProxyController(IHttpClientFactory httpClientFactory,ILogger<ApiProxyController> logger):ControllerBase{[HttpGet("dashboard/resumo")]public Task<IActionResult> Dashboard(CancellationToken ct)=>Proxy("/api/dashboard/resumo",ct);[HttpGet("tarefas")]public Task<IActionResult> Tarefas(CancellationToken ct)=>Proxy("/api/tarefas",ct);[HttpGet("project/boards")]public Task<IActionResult> Boards(CancellationToken ct)=>Proxy("/api/project/boards",ct);[HttpGet("processos/templates")]public Task<IActionResult> Processos(CancellationToken ct)=>Proxy("/api/processos/templates",ct);[HttpGet("setores")]public Task<IActionResult> Setores(CancellationToken ct)=>Proxy("/api/setores",ct);[HttpGet("usuarios")]public Task<IActionResult> Usuarios(CancellationToken ct)=>Proxy("/api/usuarios",ct);[HttpGet("catalogo/modulos")]public Task<IActionResult> Modulos(CancellationToken ct)=>Proxy("/api/catalogo/modulos",ct);async Task<IActionResult> Proxy(string path,CancellationToken ct){try{var client=httpClientFactory.CreateClient("IntegraRP.Api");var response=await client.GetAsync(path,ct);var json=await response.Content.ReadAsStringAsync(ct);return Content(json,"application/json");}catch(Exception ex){logger.LogError(ex,"Falha consumindo API em {Path}",path);return StatusCode(503,new{erro="API indisponível",path});}}}
